import { getEnvironmentUrl } from '@dynatrace-sdk/app-environment';

export const getSegmentManagementHref = () =>
  `${getEnvironmentUrl()}/ui/apps/dynatrace.settings/settings/segments`;

export const getSegmentHref = (segmentId: string) =>
  `${getEnvironmentUrl()}/ui/apps/dynatrace.settings/settings/segments/segment/${segmentId}`;
